mapper.insert:
INSERT INTO challenge_log (
    user_challenge_id, log_date, status, memo
)
VALUES (
    #{userChallengeId}, #{logDate}, #{status}, #{memo}
)

mapper.delete:
DELETE FROM challenge_log
WHERE user_challenge_id IN (
    SELECT user_challenge_id
    FROM user_challenge
    WHERE challenge_id = #{challengeId}
)

mapper.select:
SELECT COUNT(*)
FROM challenge_log
WHERE user_challenge_id = #{userChallengeId}
  AND status = #{status}
